    private List<ErroresDeAnalizadores> errores = new ArrayList<>();

    public List<ErroresDeAnalizadores> getErrores(){
        return errores;
    }

    @Override
    public void syntax_error(Symbol s){
        String lex = (s.value != null) ? s.value.toString() : symbl_name_from_id(s.sym);

        StringBuilder esperado = new StringBuilder();
        for (Integer id : expected_token_ids()) {
            String name = symbl_name_from_id(id);
            if(!name.equals("error")){
                esperado.append(name).append(" ");
            }
        }

        errores.add(new ErroresDeAnalizadores(
            lex + " -> se esperaba: " + esperado.toString(),
            "Sintáctico",
            "Creación de Formulario",
            s.left,
            s.right
        ));
    }

    @Override
    public void unrecovered_syntax_error(Symbol s){
        syntax_error(s);
    }


